interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





const getConditionIcon = (condition: string) => {
  switch (condition.toLowerCase()) {
    case 'sunny': return '☀️';
    case 'cloudy': return '☁️';
    case 'rainy': return '🌧️';
    case 'stormy': return '⛈️';
    case 'snowy': return '❄️';
    default: return '🌤️';
  }
};


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const weatherIcon = useMemo(() => getConditionIcon(props.condition), [props.condition]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-8)">
        <Stack gap="var(--ggui-spacing-6)" align="center">
          <Heading level={1}>{props.city}</Heading>

          <Stack gap="var(--ggui-spacing-2)" align="center">
            <Text size="4xl" weight="bold">{props.temperature}°{props.unit}</Text>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Text size="2xl">{weatherIcon}</Text>
              <Text variant="bodyLarge">{props.condition}</Text>
            </Stack>
          </Stack>

          <Row gap="var(--ggui-spacing-8)" justify="center">
            <Stack align="center" gap="var(--ggui-spacing-1)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
              <Text weight="semibold">{props.humidity}%</Text>
            </Stack>
            <Divider orientation="vertical" />
            <Stack align="center" gap="var(--ggui-spacing-1)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
              <Text weight="semibold">{props.windSpeed} km/h</Text>
            </Stack>
          </Row>
        </Stack>
      </Card>

      <Spacer size={24} />

      <Stack direction="horizontal" gap="var(--ggui-spacing-3)" justify="between">
        {(props.forecast || []).map((day, index) => (
          <Card key={index} padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Text variant="label">{day.day}</Text>
              <Text size="xl">{day.icon || '🌤️'}</Text>
              <Stack gap={0} align="center">
                <Text weight="semibold">{day.high}°</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{day.low}°</Text>
              </Stack>
