  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({ name: '', email: '', satisfaction: 0, features: [] as string[], comments: '' });
  const [isSubmitted, setIsSubmitted] = useState(false);

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const canProceed = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    if (step === 2) return formData.satisfaction > 0;
    if (step === 3) return formData.features.length > 0;
    return true;
  }, [step, formData]);

  const nameError = step === 1 && formData.name !== '' && formData.name.trim() === '' ? 'Name is required' : '';
  const emailError = step === 1 && formData.email !== '' && !validateEmail(formData.email) ? 'Invalid email' : '';

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>{isSubmitted ? 'Thank You!' : `Step ${step} of 4`}</Heading>
          <Progress value={isSubmitted ? 100 : (step / 4) * 100} size="md" />
        </Stack>
        {!isSubmitted ? (
          <Card padding="var(--ggui-spacing-6)">
            {step === 1 && <Stack gap="var(--ggui-spacing-3)"><Input label="Name" value={formData.name} error={nameError} onChange={(v) => setFormData({...formData, name: v})} /><Input label="Email" type="email" value={formData.email} error={emailError} onChange={(v) => setFormData({...formData, email: v})} /></Stack>}
            {step === 2 && <RadioGroup label="Satisfaction Rating" value={formData.satisfaction.toString()} onChange={(v) => setFormData({...formData, satisfaction: parseInt(v)})} options={props.satisfactionLabels.map((l, i) => ({label: l, value: (i+1).toString()}))} />}
            {step === 3 && <Stack gap="var(--ggui-spacing-2)"><Text>Features</Text>{props.featureOptions.map(f => <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={(c) => setFormData({...formData, features: c ? [...formData.features, f] : formData.features.filter(i => i !== f)})} />)}</Stack>}
            {step === 4 && <Stack gap="var(--ggui-spacing-3)"><TextArea label="Comments" maxLength={500} showCount value={formData.comments} onChange={(v) => setFormData({...formData, comments: v})} /><Heading level={3}>Review</Heading><Text>Name: {formData.name}</Text><Text>Email: {formData.email}</Text><Text>Satisfaction: {props.satisfactionLabels[formData.satisfaction - 1]}</Text><Text>Features: {formData.features.join(', ')}</Text></Stack>}
          </Card>
        ) : <Alert>Submitted!</Alert>}
        {!isSubmitted && (
          <Row gap="var(--ggui-spacing-2)" justify="between">
            <Button variant="secondary" disabled={step === 1} as={Clickable} onClick={handleBack}>Back</Button>
            {step < 4 ? <Button variant="primary" disabled={!canProceed} as={Clickable} onClick={handleNext}>Next</Button> : <Button variant="primary" as={Clickable} onClick={handleSubmit}>Submit</Button>}
          </Row>
        )}
      </Stack>
    </Container>
  );

