}





// Place helper components here if needed

const CATEGORIES = [
  { name: 'Alkali metal', color: 'var(--ggui-color-primary-300)' },
  { name: 'Alkaline earth metal', color: 'var(--ggui-color-primary-400)' },
  { name: 'Transition metal', color: 'var(--ggui-color-primary-500)' },
  { name: 'Post-transition metal', color: 'var(--ggui-color-primary-600)' },
  { name: 'Metalloid', color: 'var(--ggui-color-success-400)' },
  { name: 'Reactive nonmetal', color: 'var(--ggui-color-warning-400)' },
  { name: 'Noble gas', color: 'var(--ggui-color-error-400)' },
  { name: 'Lanthanide', color: 'var(--ggui-color-info-300)' },
  { name: 'Actinide', color: 'var(--ggui-color-info-500)' },
];

const getCategoryColor = (category?: string) => 
  CATEGORIES.find(c => c.name === category)?.color || 'var(--ggui-color-surfaceVariant)';

export default function Component(props: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selected, setSelected] = useState<(typeof props.elements)[0] | null>(null);

  const filtered = useMemo(() => {
    const s = searchTerm.toLowerCase();
    return (props.elements || []).filter(
      e => (e.name?.toLowerCase().includes(s) || e.symbol?.toLowerCase().includes(s))
    );
  }, [props.elements, searchTerm]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={1}>Periodic Table</Heading>

        <Input 
          label="Search elements" 
          placeholder="Enter name or symbol..." 
          value={searchTerm} 
          onChange={setSearchTerm} 
        />

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: '4px', padding: '16px', background: 'var(--ggui-color-surfaceVariant)', borderRadius: '8px' }}>
          {filtered.map(el => (
            <Box 
              key={el.atomicNumber} 
              as={Clickable}
              onClick={() => setSelected(el)}
              padding="4px"
              borderRadius="4px"
              background={getCategoryColor(el.category)}
              style={{ gridRow: el.row, gridColumn: el.col, cursor: 'pointer', aspectRatio: '1/1', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}
            >
              <Text size="xs" style={{ alignSelf: 'flex-start' }}>{el.atomicNumber}</Text>
              <Heading level={6}>{el.symbol}</Heading>
            </Box>
          ))}
        </Box>

        {selected && (
          <Card padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3}>{selected.name} ({selected.symbol})</Heading>
              <Text>Atomic Number: {selected.atomicNumber}</Text>
              <Text>Atomic Weight: {selected.atomicWeight}</Text>
              <Text>Category: {selected.category}</Text>
            </Stack>
          </Card>
        )}

        <Stack direction="horizontal" wrap gap="var(--ggui-spacing-4)">
          {CATEGORIES.map(c => (
            <Row key={c.name} align="center" gap="var(--ggui-spacing-2)">
              <Box background={c.color} style={{ width: '12px', height: '12px', borderRadius: '50%' }} />
              <Text variant="caption">{c.name}</Text>
            </Row>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

